import{_ as a,o,c as t,ag as r}from"./chunks/framework.BZohXCq9.js";const q=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"creator-guide/13-faq.md","filePath":"creator-guide/13-faq.md","lastUpdated":null}'),d={name:"creator-guide/13-faq.md"};function n(h,e,i,l,u,c){return o(),t("div",null,[...e[0]||(e[0]=[r('<div><h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><blockquote><p>创作过程中最常遇到的问题，这里都有答案。</p></blockquote><hr><h2 id="入门问题" tabindex="-1">入门问题 <a class="header-anchor" href="#入门问题" aria-label="Permalink to &quot;入门问题&quot;">​</a></h2><h3 id="q-我从来没写过角色卡-能用yumina吗" tabindex="-1">Q: 我从来没写过角色卡，能用Yumina吗？ <a class="header-anchor" href="#q-我从来没写过角色卡-能用yumina吗" aria-label="Permalink to &quot;Q: 我从来没写过角色卡，能用Yumina吗？&quot;">​</a></h3><p>完全可以。Yumina的编辑器是可视化的，不需要编程基础。最简单的世界只需要填一段角色描述和一句开场白就能跑起来。建议你先去 <a href="https://yumina.io" target="_blank" rel="noreferrer">yumina.io</a> 玩几个别人做好的世界，感受一下成品效果，然后跟着教程一步步来。详见 <a href="./00-welcome.html">欢迎</a> 和 <a href="./01-core-concepts.html">核心概念速览</a>。</p><h3 id="q-创建一个最简单的世界需要哪些步骤" tabindex="-1">Q: 创建一个最简单的世界需要哪些步骤？ <a class="header-anchor" href="#q-创建一个最简单的世界需要哪些步骤" aria-label="Permalink to &quot;Q: 创建一个最简单的世界需要哪些步骤？&quot;">​</a></h3><p>三步就够了：1）点 <strong>创建（Create）</strong> 新建一个世界；2）在 <strong>词条（Lorebook）</strong> 里创建一个 <code>character</code> 角色词条，写上角色的人设，打开 <strong>始终发送（Always Send）</strong>；3）在 <strong>开场白（First Message）</strong> 里写一条开场白。点 <strong>保存（Save）</strong> 之后就能开始聊了。变量、行为、渲染器这些都是可选的进阶功能，后面再加不迟。</p><h3 id="q-yumina支持哪些ai模型" tabindex="-1">Q: Yumina支持哪些AI模型？ <a class="header-anchor" href="#q-yumina支持哪些ai模型" aria-label="Permalink to &quot;Q: Yumina支持哪些AI模型？&quot;">​</a></h3><p>Yumina通过 OpenRouter 接入模型，基本上 OpenRouter 上有的模型都能用——包括 Claude、GPT、Gemini、DeepSeek、Llama 等主流模型。你需要在设置里配置自己的 API Key。不同模型对指令格式的遵从度不同，建议在世界设置里调好 temperature 等参数来适配你选的模型。详见 <a href="./10-ai-settings.html">AI 模型与设置</a>。</p><h3 id="q-我的世界数据保存在哪里-会丢吗" tabindex="-1">Q: 我的世界数据保存在哪里？会丢吗？ <a class="header-anchor" href="#q-我的世界数据保存在哪里-会丢吗" aria-label="Permalink to &quot;Q: 我的世界数据保存在哪里？会丢吗？&quot;">​</a></h3><p>你的世界数据保存在 Yumina 的服务器数据库里，正常使用不会丢失。但养成备份习惯总是好的——在编辑器的 <strong>概览（Overview）</strong> 里可以导入导出世界 JSON 文件，存到本地当离线备份。如果你改坏了什么东西，还能从备份导入恢复。详见 <a href="./11-publish-and-share.html">发布、导出与 Bundle</a>。</p><hr><h2 id="词条与世界书" tabindex="-1">词条与世界书 <a class="header-anchor" href="#词条与世界书" aria-label="Permalink to &quot;词条与世界书&quot;">​</a></h2><h3 id="q-词条太多了-怎么组织" tabindex="-1">Q: 词条太多了，怎么组织？ <a class="header-anchor" href="#q-词条太多了-怎么组织" aria-label="Permalink to &quot;Q: 词条太多了，怎么组织？&quot;">​</a></h3><p>用文件夹。编辑器支持创建文件夹，按逻辑分组管理词条——比如按角色、按场景、按功能分。文件夹纯粹是组织工具，不影响词条的运行时行为。另外善用 <code>tags</code> 标签字段，方便筛选和查找。详见 <a href="./03-entries-and-lorebook.html">词条与世界书</a> 的&quot;文件夹组织&quot;部分。</p><h3 id="q-关键词触发不生效怎么办" tabindex="-1">Q: 关键词触发不生效怎么办？ <a class="header-anchor" href="#q-关键词触发不生效怎么办" aria-label="Permalink to &quot;Q: 关键词触发不生效怎么办？&quot;">​</a></h3><p>排查几个常见原因：1）检查词条的 <code>enabled</code> 是不是 <code>true</code>；2）确认 <code>lorebookScanDepth</code> 够大——默认只扫描最近 2 条消息，如果关键词出现在更早的消息里就扫不到；3）如果用了二级关键词（<code>secondaryKeywords</code>），检查逻辑是不是设对了；4）如果开了 <code>matchWholeWords</code>，注意中文一般不需要全词匹配。详见 <a href="./03-entries-and-lorebook.html">词条与世界书</a> 的&quot;关键词匹配&quot;部分。</p><h3 id="q-alwayssend的词条和关键词触发的词条有什么区别" tabindex="-1">Q: alwaysSend的词条和关键词触发的词条有什么区别？ <a class="header-anchor" href="#q-alwayssend的词条和关键词触发的词条有什么区别" aria-label="Permalink to &quot;Q: alwaysSend的词条和关键词触发的词条有什么区别？&quot;">​</a></h3><p><code>alwaysSend: true</code> 的词条每次对话都会被塞进提示词里，不管玩家说了什么——适合核心人设、基础世界观这类必须时刻生效的内容。关键词触发的词条只有在最近消息中出现匹配词时才激活——适合特定场景、地点、NPC 等按需投放的内容。两者的区别本质上是&quot;常驻&quot;还是&quot;按需&quot;，合理搭配可以节省大量 token 预算。详见 <a href="./03-entries-and-lorebook.html">词条与世界书</a>。</p><h3 id="q-示例对话要怎么写才有效" tabindex="-1">Q: 示例对话要怎么写才有效？ <a class="header-anchor" href="#q-示例对话要怎么写才有效" aria-label="Permalink to &quot;Q: 示例对话要怎么写才有效？&quot;">​</a></h3><p>用 <code>&lt;START&gt;</code> 分隔不同的对话段落，用 <code>{{user}}:</code> 和 <code>{{char}}:</code> 标记发言者。每段示例应该展示角色独特的说话方式、语气和反应模式，而不是单纯的信息传递。两到三段高质量示例比十段平庸的示例有效得多。词条的 role 设为 <code>example</code>，section 放在 <code>examples</code> 区域。详见 <a href="./03-entries-and-lorebook.html">词条与世界书</a> 的&quot;示例对话格式&quot;部分。</p><hr><h2 id="变量与指令" tabindex="-1">变量与指令 <a class="header-anchor" href="#变量与指令" aria-label="Permalink to &quot;变量与指令&quot;">​</a></h2><h3 id="q-ai不按格式写指令怎么办" tabindex="-1">Q: AI不按格式写指令怎么办？ <a class="header-anchor" href="#q-ai不按格式写指令怎么办" aria-label="Permalink to &quot;Q: AI不按格式写指令怎么办？&quot;">​</a></h3><p>引擎已经自动告诉 AI 指令格式了，所以问题通常不是&quot;AI 不知道格式&quot;，而是&quot;AI 不确定什么时候该用&quot;。几个办法：1）在变量的 <code>behaviorRules</code> 里把触发条件写得更具体——比如&quot;玩家受到攻击时扣减，每次扣 10-30&quot;比&quot;受伤时扣减&quot;更好；2）在 <code>post-history</code> 区域加一条词条提醒 AI 别忘了输出指令；3）降低 <code>temperature</code>（比如 0.5-0.7），让 AI 更老实地遵循规则；4）不同模型对指令的遵从度差异很大，换个模型试试也是思路。详见 <a href="./05-directives-and-macros.html">AI 指令与宏</a> 和 <a href="./10-ai-settings.html">AI 模型与设置</a>。</p><h3 id="q-变量值突然变成奇怪的值-怎么排查" tabindex="-1">Q: 变量值突然变成奇怪的值，怎么排查？ <a class="header-anchor" href="#q-变量值突然变成奇怪的值-怎么排查" aria-label="Permalink to &quot;Q: 变量值突然变成奇怪的值，怎么排查？&quot;">​</a></h3><p>先看 AI 的原始回复里写了什么指令——有时候 AI 会写出你没预想到的操作。然后检查是不是有规则在后台悄悄修改了这个变量（规则的 <code>modify-variable</code> 动作）。对于 number 类型变量，确认你设了合理的 <code>min</code> 和 <code>max</code>，引擎会自动钳制超出范围的值。如果还是找不到原因，在编辑器里逐条检查引用了这个变量的所有规则和词条。</p><h3 id="q-json类型的变量怎么用" tabindex="-1">Q: JSON类型的变量怎么用？ <a class="header-anchor" href="#q-json类型的变量怎么用" aria-label="Permalink to &quot;Q: JSON类型的变量怎么用？&quot;">​</a></h3><p>JSON 变量可以存复杂数据结构——对象、数组、嵌套结构都行。最常见的用法是做背包（JSON 数组）和角色关系网（JSON 对象）。操作方式包括 <code>merge</code>（合并对象）、<code>push</code>（数组追加）、<code>delete</code>（删除键或元素），还支持点号路径深入操作嵌套结构，比如 <code>[relationships.aria.trust: +10]</code>。详见 <a href="./04-variables.html">变量系统</a> 的&quot;嵌套 JSON 路径&quot;部分。</p><h3 id="q-我能有多少个变量-有限制吗" tabindex="-1">Q: 我能有多少个变量？有限制吗？ <a class="header-anchor" href="#q-我能有多少个变量-有限制吗" aria-label="Permalink to &quot;Q: 我能有多少个变量？有限制吗？&quot;">​</a></h3><p>引擎层面没有硬性数量限制。但每个变量的当前值都会被写进发给 AI 的提示词里，变量太多会占用大量 token 预算，导致 AI 能&quot;看到&quot;的对话历史变短。实际上大多数世界用 5-20 个变量就够了。如果你需要存大量数据，考虑用一个 JSON 类型变量把相关数据打包在一起，比一堆零散变量更高效。</p><hr><h2 id="行为引擎" tabindex="-1">行为引擎 <a class="header-anchor" href="#行为引擎" aria-label="Permalink to &quot;行为引擎&quot;">​</a></h2><h3 id="q-行为没有触发-怎么排查" tabindex="-1">Q: 行为没有触发，怎么排查？ <a class="header-anchor" href="#q-行为没有触发-怎么排查" aria-label="Permalink to &quot;Q: 行为没有触发，怎么排查？&quot;">​</a></h3><p>按顺序检查这几项：1）行为是不是启用状态，有没有被其他行为禁用了；2）WHEN 触发器类型对不对——比如你选了&quot;变量穿过阈值&quot;但变量根本没变化过那个阈值；3）ONLY IF 条件是不是全部满足（注意 <code>conditionLogic</code> 是 <code>all</code> 还是 <code>any</code>）；4）是不是在冷却期（<code>cooldownTurns</code>）；5）是不是已经达到最大触发次数（<code>maxFireCount</code>）。详见 <a href="./06-rules-engine.html">行为规则引擎</a> 的&quot;评估流程&quot;部分。</p><h3 id="q-多个行为同时触发时-执行顺序是什么" tabindex="-1">Q: 多个行为同时触发时，执行顺序是什么？ <a class="header-anchor" href="#q-多个行为同时触发时-执行顺序是什么" aria-label="Permalink to &quot;Q: 多个行为同时触发时，执行顺序是什么？&quot;">​</a></h3><p>按 <code>priority</code> 字段从高到低排序。数字越大的行为越先被评估和执行。比如一条 priority 为 100 的&quot;死亡判定&quot;行为会比 priority 为 50 的&quot;低血量警告&quot;行为先执行。如果两条行为 priority 相同，则按它们在列表中的定义顺序执行。建议给重要行为分配更高的 priority 值。详见 <a href="./06-rules-engine.html">行为规则引擎</a> 的&quot;优先级&quot;部分。</p><h3 id="q-行为可以互相控制吗" tabindex="-1">Q: 行为可以互相控制吗？ <a class="header-anchor" href="#q-行为可以互相控制吗" aria-label="Permalink to &quot;Q: 行为可以互相控制吗？&quot;">​</a></h3><p>可以，这是行为引擎最强大的特性之一。用&quot;启用/禁用行为&quot;动作可以启用或禁用其他行为。典型场景：行为 A 监听&quot;进入地下城&quot;关键词，触发后启用一个初始状态为禁用的怪物遭遇行为 B；离开地下城时再禁用它。你可以做出&quot;平时休眠、被激活后才开始工作&quot;的行为链。详见 <a href="./06-rules-engine.html">行为规则引擎</a> 的&quot;规则互控&quot;部分。</p><h3 id="q-cooldownturns和maxfirecount怎么配合使用" tabindex="-1">Q: cooldownTurns和maxFireCount怎么配合使用？ <a class="header-anchor" href="#q-cooldownturns和maxfirecount怎么配合使用" aria-label="Permalink to &quot;Q: cooldownTurns和maxFireCount怎么配合使用？&quot;">​</a></h3><p><code>cooldownTurns</code> 控制触发间隔——行为触发一次后要冷却几个回合才能再次触发，适合&quot;不要太频繁&quot;的场景，比如每隔至少 5 回合才提醒一次饥饿。<code>maxFireCount</code> 控制总次数上限——行为一生最多触发这么多次，之后永远不再触发，适合一次性事件，比如教程提示设 <code>maxFireCount: 1</code>。两者可以同时使用：比如一个&quot;隐藏剧情提示&quot;行为设 <code>cooldownTurns: 10</code> + <code>maxFireCount: 3</code>，意思是最多提示 3 次，每次之间至少间隔 10 回合。</p><hr><h2 id="组件与渲染" tabindex="-1">组件与渲染 <a class="header-anchor" href="#组件与渲染" aria-label="Permalink to &quot;组件与渲染&quot;">​</a></h2><h3 id="q-不会写tsx-能用自定义渲染器吗" tabindex="-1">Q: 不会写TSX，能用自定义渲染器吗？ <a class="header-anchor" href="#q-不会写tsx-能用自定义渲染器吗" aria-label="Permalink to &quot;Q: 不会写TSX，能用自定义渲染器吗？&quot;">​</a></h3><p>可以试试。几个入手方式：1）用编辑器里的 <strong>进入 Studio（Enter Studio）</strong>，让 AI Assistant 帮你生成代码；2）把你想要的效果用文字描述给外部 AI（比如 Claude），让它帮你生成 TSX 代码，粘贴到编辑器里；3）从文档里的模板例子复制粘贴，改改颜色和文字。编辑器会实时编译并提示错误（底部显示 <strong>Compile Status</strong>），可以边改边调。详见 <a href="./07-components.html">自定义前端指南</a> 和 <a href="./08-message-renderer.html">自定义消息渲染器</a>。</p><h3 id="q-组件显示在哪里-能自定义位置吗" tabindex="-1">Q: 组件显示在哪里？能自定义位置吗？ <a class="header-anchor" href="#q-组件显示在哪里-能自定义位置吗" aria-label="Permalink to &quot;Q: 组件显示在哪里？能自定义位置吗？&quot;">​</a></h3><p>内置组件（stat-bar、text-display 等）显示在聊天窗口上方的 header 横栏里，目前 <code>placement</code> 只支持 <code>&quot;header&quot;</code> 这一个位置。如果你需要更灵活的布局——比如侧边栏、全屏面板——可以用 <code>customComponents</code> 写自定义 TSX 组件，或者开启 <code>fullScreenComponent: true</code> 让自定义组件占据整个屏幕。组件之间的排列顺序由 <code>order</code> 字段控制，数字越小越靠前。详见 <a href="./07-components.html">组件系统</a>。</p><h3 id="q-messagerenderer和customcomponents有什么区别" tabindex="-1">Q: messageRenderer和customComponents有什么区别？ <a class="header-anchor" href="#q-messagerenderer和customcomponents有什么区别" aria-label="Permalink to &quot;Q: messageRenderer和customComponents有什么区别？&quot;">​</a></h3><p><code>messageRenderer</code> 替换的是每条聊天消息的显示方式——它接管 AI 回复的渲染，让你把纯文本变成气泡对话、视觉小说对话框、战斗日志等。<code>customComponents</code> 是在聊天界面旁边额外添加的独立 UI 面板，比如角色创建界面、游戏侧边栏、地图。简单说：messageRenderer 改的是&quot;消息长什么样&quot;，customComponents 加的是&quot;消息旁边还有什么&quot;。两者可以同时使用，底层数据结构都是 <code>CustomComponent</code>。详见 <a href="./08-message-renderer.html">自定义消息渲染器</a>。</p><hr><h2 id="发布与分享" tabindex="-1">发布与分享 <a class="header-anchor" href="#发布与分享" aria-label="Permalink to &quot;发布与分享&quot;">​</a></h2><h3 id="q-发布后还能修改吗" tabindex="-1">Q: 发布后还能修改吗？ <a class="header-anchor" href="#q-发布后还能修改吗" aria-label="Permalink to &quot;Q: 发布后还能修改吗？&quot;">​</a></h3><p>可以。发布后你随时可以回到编辑器修改世界内容，保存即生效——新玩家会立刻看到最新版本。如果你想暂时下架，可以把状态改为 <code>unpublished</code>，已经在玩的用户会看到只读提示。不过要注意：如果你修改了变量定义（比如删掉了某个变量），引擎会自动处理老玩家的存档兼容——新增的变量用默认值补上，删掉的变量会被过滤掉，不会搞坏老玩家的存档。详见 <a href="./11-publish-and-share.html">发布、导出与 Bundle</a>。</p><h3 id="q-怎么让更多人发现我的世界" tabindex="-1">Q: 怎么让更多人发现我的世界？ <a class="header-anchor" href="#q-怎么让更多人发现我的世界" aria-label="Permalink to &quot;Q: 怎么让更多人发现我的世界？&quot;">​</a></h3><p>几个关键点：1）上传一张好看的缩略图——没图的世界在 Hub 里几乎不会被点开；2）写一段吸引人的描述，讲清楚这个世界是什么、有什么好玩的；3）加 3-5 个相关标签，想想玩家会搜什么词；4）写一个精彩的开场白（greeting），第一印象决定玩家会不会继续玩下去；5）发布前自己从头玩一遍，确保体验流畅。详见 <a href="./11-publish-and-share.html">发布、导出与 Bundle</a> 的&quot;发布前检查清单&quot;。</p><h3 id="q-bundle和完整世界导出有什么区别" tabindex="-1">Q: Bundle和完整世界导出有什么区别？ <a class="header-anchor" href="#q-bundle和完整世界导出有什么区别" aria-label="Permalink to &quot;Q: Bundle和完整世界导出有什么区别？&quot;">​</a></h3><p>完整世界导出是整个 <code>WorldDefinition</code> 的 JSON 文件——包含所有词条、变量、规则、组件、设置，一个不漏，适合做备份或把整个世界分享给别人。Bundle 是世界的&quot;零件包&quot;——你可以只挑选一部分内容（比如一套战斗规则 + 相关变量 + 组件）打包出来，别人可以把这个零件包安装到自己的世界里。简单说：世界导出是&quot;整辆车&quot;，Bundle 是&quot;发动机总成&quot;。详见 <a href="./11-publish-and-share.html">发布、导出与 Bundle</a> 的&quot;Bundle 系统&quot;部分。</p></div>',1)])])}const m=a(d,[["render",n]]);export{q as __pageData,m as default};
